import { createCompanyMark } from '../modules/companies/view.js';
import { createProblemControllerBundle } from '../modules/problems/controllerBundle.js';
import { createProblemsRuntimeBundle } from '../modules/problems/runtimeBundle.js';

export function createAppProblemControllerBundles(deps = {}) {
  const {
    applyProblemNavigationFilters,
    clearProblemLookupCaches,
    cloudApi,
    companyTierWeight,
    companies,
    documentRef: document,
    elements: els,
    emptyBlock,
    formatCategoryLabel,
    formatProblemTag,
    getCatalogProblems,
    getCompanyAliases,
    getCompanyProblemStats,
    getInitials,
    getLanguage,
    getLibrarySourceLabel,
    getLocale,
    getProblemBrowserMatches,
    getProblemCompanies,
    getProblemCompletionCount,
    getProblemDisplayTitle,
    getProblemExcerptText,
    getProblemFilterState,
    getProblemFilterValue,
    getProblemPersonalState,
    getProblemSocial,
    getLeetcodeHotCompletionStats,
    importLeetcodeHotItems,
    isCatalogProblem,
    isDisabledProblemId,
    isDisabledProblemSource,
    isHiddenProblemTag,
    isLeetcodeHotExpanded,
    mergeProblems,
    normalizeCategory,
    normalizeLeetcodeHot100Done: normalizeLeetcodeHot100DoneValue,
    openProblemDetail,
    pageSize,
    problemDetailState,
    problemSearchRecordCache,
    problemSocialState,
    problemTagLabels,
    problemMatchesCompany,
    problemMatchesDifficulty,
    problemMatchesSource,
    problemMatchesTheme,
    refreshIcons,
    renderInterviewSetup,
    renderLeetcodeHot100,
    renderProblemDetail,
    renderProblemPagination,
    renderProblems,
    renderSummary,
    requestProblemSocial,
    resetProblemPagination,
    saveState,
    setLeetcodeHotExpanded,
    setProblemFilterState,
    skillDefs,
    t,
    toggleProblemCompleted,
    toggleProblemSaved,
    userState,
    windowRef: window
  } = deps;

  const problemsRuntimeBundle = createProblemsRuntimeBundle({
    windowRef: window,
    getState: () => userState.value,
    cloudApi,
    isCatalogProblem,
    isDisabledProblemSource,
    getUserCatalogProblems: deps.getUserCatalogProblems,
    mergeProblems,
    isDisabledProblemId,
    clearProblemLookupCaches,
    saveState,
    renderProblems,
    renderInterviewSetup,
    searchDebounceMs: deps.searchDebounceMs,
    getSearchQuery: () => els.problemSearch?.value || "",
    getViewMode: () => getProblemFilterValue("viewMode"),
    setViewMode: (value) => { setProblemFilterState({ viewMode: value }); },
    clearDetail: () => { problemDetailState.clear(); },
    resetPagination: resetProblemPagination,
    renderSearchResults: () => renderProblems({ resultsOnly: true }),
    getMatches: getProblemBrowserMatches,
    openProblem: openProblemDetail,
    getSocial: () => problemSocialState.getSocial(),
    setSocial: (social) => problemSocialState.setSocial(social),
    getSelectedProblemDetailId: () => problemDetailState.getDetailId(),
    getProblemById: (problemId) => userState.value.problems.find((item) => item.id === problemId),
    requestSocial: (problemId) => requestProblemSocial(cloudApi, problemId),
    setNotice: (notice) => problemSocialState.setNotice(notice),
    t
  });

  const problemControllerBundle = createProblemControllerBundle({
    elements: els,
    documentRef: document,
    windowRef: window,
    pageSize,
    getState: () => userState.value,
    getCatalogProblems,
    getFilterState: getProblemFilterState,
    getLocale,
    getLanguage,
    getSearchQuery: () => els.problemSearch?.value || "",
    searchRecordCache: problemSearchRecordCache,
    tagLabels: problemTagLabels,
    normalizeCategory,
    formatCategoryLabel,
    formatTag: formatProblemTag,
    isHiddenTag: isHiddenProblemTag,
    getCompletionCount: getProblemCompletionCount,
    getLeetcodeHotCompletionStats,
    leetcodeHotItems: importLeetcodeHotItems,
    normalizeLeetcodeHot100Done: (doneIds) => {
      if (typeof normalizeLeetcodeHot100DoneValue === "function") {
        return normalizeLeetcodeHot100DoneValue(doneIds, importLeetcodeHotItems);
      }
      const valid = new Set((Array.isArray(importLeetcodeHotItems) ? importLeetcodeHotItems : []).map((item) => item.id));
      return [...new Set(Array.isArray(doneIds) ? doneIds.map(String) : [])]
        .filter((id) => valid.has(id));
    },
    skillDefs,
    isCatalogProblem,
    matchesSource: problemMatchesSource,
    matchesCompany: problemMatchesCompany,
    matchesTheme: problemMatchesTheme,
    matchesDifficulty: problemMatchesDifficulty,
    isLeetcodeExpanded: isLeetcodeHotExpanded,
    setLeetcodeExpanded: setLeetcodeHotExpanded,
    renderLeetcodeHot100,
    saveState,
    renderSummary,
    renderSkills: () => {},
    refreshIcons,
    emptyBlock,
    getPersonalState: getProblemPersonalState,
    getDisplayTitle: getProblemDisplayTitle,
    getPromptText: getProblemExcerptText,
    getSocial: getProblemSocial,
    getCompanies: getProblemCompanies,
    getCompanyAliases,
    openProblemDetail,
    toggleCompleted: toggleProblemCompleted,
    toggleSaved: toggleProblemSaved,
    cancelSearchRender: problemsRuntimeBundle.cancelSearchRender,
    getSelectedDetailId: () => problemDetailState.getDetailId(),
    setSelectedDetailId: (detailId) => problemDetailState.setDetailId(detailId),
    renderProblemDetail,
    hidePagination: deps.hideProblemPagination,
    getPage: () => deps.getProblemPage(),
    setPage: (page) => deps.setProblemPage(page),
    renderPagination: renderProblemPagination,
    companies,
    getCompanyFilter: () => getProblemFilterValue("company"),
    getCompanyProblemStats,
    companyTierWeight,
    createCompanyMark: (company) => createCompanyMark(company, { getInitials }),
    getSocialNotice: () => problemSocialState.getNotice(),
    getSourceLabel: getLibrarySourceLabel,
    applyNavigationFilters: applyProblemNavigationFilters,
    resetPagination: resetProblemPagination,
    renderProblems,
    t
  });

  return {
    problemBrowserController: problemControllerBundle.browserController,
    leetcodeHotController: problemControllerBundle.leetcodeHotController,
    problemsRuntime: problemsRuntimeBundle.runtime,
    handleProblemSearchInput: problemsRuntimeBundle.handleSearchInput,
    handleProblemSearchKeydown: problemsRuntimeBundle.handleSearchKeydown,
    scheduleProblemSearchRender: problemsRuntimeBundle.scheduleSearchRender,
    cancelProblemSearchRender: problemsRuntimeBundle.cancelSearchRender,
    getProblemThemeEntries: problemControllerBundle.getProblemThemeEntries,
    renderProblemThemeFilter: problemControllerBundle.renderProblemThemeFilter,
    renderProblemDifficultyFilter: problemControllerBundle.renderProblemDifficultyFilter,
    buildProblemProgressItems: problemControllerBundle.buildProblemProgressItems,
    renderProgressGroup: problemControllerBundle.renderProgressGroup,
    renderProblemCompletionDashboard: problemControllerBundle.renderProblemCompletionDashboard,
    getProblemCollectionEntries: problemControllerBundle.getProblemCollectionEntries,
    renderProblemCollectionGrid: problemControllerBundle.renderProblemCollectionGrid,
    handleProblemCollectionClick: problemControllerBundle.handleProblemCollectionClick
  };
}
